    {
      "id": "I3_LLM_TARGET",
      "status": "met",
      "evidence": [
        {"source": "T", "quote": "A Systematic Survey of Prompt Engineering in Large Language Models: Techniques and Applications"},
        {"source": "S1", "quote": "Prompt engineering has emerged as an indispensable technique for extending the capabilities of large language models (LLMs) and vision-language models (VLMs)."}
      ],
      "reason": "The title and abstract explicitly mention large language models as the target."
    },
    {
      "id": "I4_PRACTITIONER",
      "status": "unclear",
      "evidence": [
        {"source": "S2", "quote": "This approach leverages task-specific instructions, known as prompts, to enhance model efficacy without modifying the core model parameters."},
        {"source": "S4", "quote": "Prompts can be natural language instructions that provide context to guide the model or learned vector representations that activate relevant knowledge."}
      ],
      "reason": "S2 suggests the approach does not require modifying model parameters, aligning with practitioner applicability, but S4 introduces learned vector representations, which may require training, making it unclear whether all described techniques are applicable without training."
    },
    {
      "id": "E1_NO_ACTIONABLE_TECHNIQUE",
